window.NZ_OPISY=window.NZ_OPISY||{};window.NZ_OPISY["b"]={"Bartosz": "<b>Bartosz</b> – staropolska skrócona forma imienia <a href=\"https://pl.wikipedia.org/wiki/Bart%C5%82omiej\" target=\"_blank\" rel=\"noopener noreferrer\">Bartłomiej</a> (jedna z wielu wówczas istniejących, inne to np. Bartek, Bartko, Bartusz czy Bartysz). W Polsce używane w średniowieczu (pierwszy zapis w 1216 r.). Imię popularne w tej formie stało się ponownie w ostatnich dziesięcioleciach XX w.", "Bartłomiej": "<b>Bartłomiej</b> (od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_aramejski\" target=\"_blank\" rel=\"noopener noreferrer\">aram.</a>&#160;&#8207;בר-תולמי&#8206; – „syn oracza” lub „syn Tolmy”) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_aramejski\" target=\"_blank\" rel=\"noopener noreferrer\">aramejskiego</a>.", "Bogdan": "<b>Bogdan</b>, <b>Bogudan</b>, <b>Bogodan</b>, <b>Bohdan</b>, <b>Bodan</b> – męskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię pochodzenia słowiańskiego</a>.", "Bogusław": "<b>Bogusław</b>, <b>Bogosław</b>, <b>Bohusław</b>, <b>Bogsław</b> – <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">staropolskie imię</a> męskie. Imię <i>Bogusław</i> jest przykładem <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_staropolski\" target=\"_blank\" rel=\"noopener noreferrer\">staropolskiego</a>, złożonego, osobowego imienia dwuczłonowego, które jest <a href=\"https://pl.wikipedia.org/wiki/Relikt\" target=\"_blank\" rel=\"noopener noreferrer\">reliktem</a> <a href=\"https://pl.wikipedia.org/wiki/Poga%C5%84stwo\" target=\"_blank\" rel=\"noopener noreferrer\">pogańskich</a> imion używanych we wczesnym średniowieczu przez <a href=\"https://pl.wikipedia.org/wiki/S%C5%82owianie\" target=\"_blank\" rel=\"noopener noreferrer\">Słowian</a>. Składa się z członu <i>Bogu-</i> („Bóg”, „Boga”, ale pierwotnie „los, dola, szczęście”) oraz <i>-sław</i> („sława”). Być może znaczyło pierwotnie „ten, który sławi los”, a później „sławiący Boga”. <a href=\"https://pl.wikipedia.org/wiki/Witold_Taszycki\" target=\"_blank\" rel=\"noopener noreferrer\">Witold Taszycki</a> zaliczył je do grupy najstarszych polskich imion osobowych&#8201;.", "Bronisław": "<b>Bronisław</b>, <b>Bronsław</b>, <b>Barnisław</b>, (zniem.) <b>Brunisław</b>, <b>Brosław</b> – męskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię pochodzenia słowiańskiego</a>.", "Błażej": "<b>Błażej</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od słowa „blaesus” oznaczającego „seplenić”.", "Bolesław": "<b>Bolesław</b> (<i>bole(j)</i> + <i>sław</i> – „bardziej sławny”) – <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">słowiańskie imię</a> męskie. Dawniej zapisywane również w formie skróconej Bosław lub Bolko. Imię dynastyczne w polskiej dynastii <a href=\"https://pl.wikipedia.org/wiki/Piastowie\" target=\"_blank\" rel=\"noopener noreferrer\">Piastów</a> oraz czeskiej <a href=\"https://pl.wikipedia.org/wiki/Przemy%C5%9Blidzi\" target=\"_blank\" rel=\"noopener noreferrer\">Przemyślidów</a>. Do dynastii piastowskiej zostało zapożyczone od <a href=\"https://pl.wikipedia.org/wiki/Przemy%C5%9Blidzi\" target=\"_blank\" rel=\"noopener noreferrer\">Przemyślidów</a> poprzez dziedziczenie po linii żeńskiej (imię kognacyjne). Ostatnim jego piastowskim przedstawicielem był Piast mazowiecki <a href=\"https://pl.wikipedia.org/wiki/Boles%C5%82aw_V_warszawski\" target=\"_blank\" rel=\"noopener noreferrer\">Bolesław V, książę warszawski</a> (XV w.).", "Bernard": "<b>Bernard</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Imiona_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>. Wywodzi się od słowa oznaczającego „silny niedźwiedź”. (staroniemieckie: bero, bern – niedźwiedź i hart – silny). Wśród patronów – św. <a href=\"https://pl.wikipedia.org/wiki/Bernard_z_Clairvaux\" target=\"_blank\" rel=\"noopener noreferrer\">Bernard z Clairvaux</a>. Formą oboczna tego imienia jest imię <i>Berard</i> (<a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a> <i>Berardus</i>), zapisywane czasami jako: Berald(us), Gerard(us).", "Bohdan": "<b>Bohdan</b> – męskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię pochodzenia słowiańskiego</a>.", "Borys": "<b>Borys</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Protobu%C5%82garzy\" target=\"_blank\" rel=\"noopener noreferrer\">protobułgarskiego</a>. W języku <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_protobu%C5%82garski\" target=\"_blank\" rel=\"noopener noreferrer\">protobułgarskim</a> imię to oznaczało, według jednych opracowań, „wilk”, „irbis śnieżny”, według innych „mały”, „niski”, lub „waleczny”.", "Bruno": "<b>Bruno, Brunon</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>. Wywodzi się od słowa <i>brün</i> oznaczającego „<a href=\"https://pl.wikipedia.org/wiki/Nied%C5%BAwied%C5%BA_brunatny\" target=\"_blank\" rel=\"noopener noreferrer\">niedźwiedź</a>” lub „brunatny”. Forma <b>Brunon</b> powstała pod wpływem <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskim</a>. W Polsce imię Bruno po raz pierwszy zanotowano w <a href=\"https://pl.wikipedia.org/wiki/1236\" target=\"_blank\" rel=\"noopener noreferrer\">1236</a> roku.", "Bogumił": "<b>Bogumił</b>, <b>Bogomił</b>, <b>Bogmił</b>, <b>Bogomieł</b>, <b>Bogmieł</b>, <b>Bogumieł</b> – <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">staropolskie imię</a> męskie. Wywodzi się ze złożenia członów: <i>Bog-</i> („Bóg”, ale pierwotnie w znaczeniu „los, dola, szczęście”) oraz <i>-mił</i> („miły”). Oznacza więc: „miły Bogu” (lecz uprzednio mogło znaczyć „ten, któremu los sprzyja”). <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">Imiona słowiańskie</a> ze składnikami <i>Bog-</i> (np. Bogumił czy Bogusław) mogą być także słowiańskim naśladownictwem irańskich imion używanych w czasach od <a href=\"https://pl.wikipedia.org/wiki/VI_wiek_p.n.e.\" target=\"_blank\" rel=\"noopener noreferrer\">VI</a> do <a href=\"https://pl.wikipedia.org/wiki/IV_wiek_p.n.e.\" target=\"_blank\" rel=\"noopener noreferrer\">IV wieku p.n.e.</a>, takich jak Bagafarna („mający sławę od Boga”).", "Benedykt": "<b>Benedykt</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od słowa <i>benedictus</i>, oznaczającego „tego, o którym się dobrze mówi”; „tego, któremu się dobrze życzy”. Znanym imiennikiem był <a href=\"https://pl.wikipedia.org/wiki/Benedykt_z_Nursji\" target=\"_blank\" rel=\"noopener noreferrer\">Benedykt z Nursji</a>, założyciel <a href=\"https://pl.wikipedia.org/wiki/Benedyktyni\" target=\"_blank\" rel=\"noopener noreferrer\">opactwa benedyktyńskiego</a> na <a href=\"https://pl.wikipedia.org/wiki/Monte_Cassino\" target=\"_blank\" rel=\"noopener noreferrer\">Monte Cassino</a>, i <a href=\"https://pl.wikipedia.org/wiki/Baruch_Spinoza\" target=\"_blank\" rel=\"noopener noreferrer\">Spinoza</a>.", "Beniamin": "<b>Beniamin</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia biblijnego, oznaczające dosłownie „syn południa” lub „syn prawicy” (w <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">języku hebrajskim</a> północ jest utożsamiana z lewą, a południe z prawą stroną). Beniamin <a href=\"https://pl.wikipedia.org/wiki/Imieniny\" target=\"_blank\" rel=\"noopener noreferrer\">imieniny</a> obchodzi <a href=\"https://pl.wikipedia.org/wiki/31_marca\" target=\"_blank\" rel=\"noopener noreferrer\">31 marca</a> i <a href=\"https://pl.wikipedia.org/wiki/19_grudnia\" target=\"_blank\" rel=\"noopener noreferrer\">19 grudnia</a>.", "Brajan": "<b>Brajan</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_angielski\" target=\"_blank\" rel=\"noopener noreferrer\">ang.</a>&#160;<em>Brian</em>, <i>Bryan</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Celtowie\" target=\"_blank\" rel=\"noopener noreferrer\">celtyckiego</a>, wywodzące się najprawdopodobniej od słów <i>bruaich</i> „wzgórze”, <i>brigh</i> „wysoki”; „szlachetnie urodzony” lub <i>bri</i> „silny”. Do Polski trafiło z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_angielski\" target=\"_blank\" rel=\"noopener noreferrer\">języka angielskiego</a> i zaczęło być nadawane częściej dopiero w latach 90. XX wieku. Popularne jest w krajach anglosaskich, gdzie funkcjonuje zarówno jako samodzielne imię, jak i jako forma <a href=\"https://pl.wikipedia.org/wiki/Zdrobnienie\" target=\"_blank\" rel=\"noopener noreferrer\">zdrobniała</a> od <a href=\"https://pl.wikipedia.org/wiki/Bernard_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Bernarda</a> i <a href=\"https://pl.wikipedia.org/wiki/Barnaba\" target=\"_blank\" rel=\"noopener noreferrer\">Barnaby</a>.", "Brunon": "<b>Bruno, Brunon</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>. Wywodzi się od słowa <i>brün</i> oznaczającego „<a href=\"https://pl.wikipedia.org/wiki/Nied%C5%BAwied%C5%BA_brunatny\" target=\"_blank\" rel=\"noopener noreferrer\">niedźwiedź</a>” lub „brunatny”. Forma <b>Brunon</b> powstała pod wpływem <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskim</a>. W Polsce imię Bruno po raz pierwszy zanotowano w <a href=\"https://pl.wikipedia.org/wiki/1236\" target=\"_blank\" rel=\"noopener noreferrer\">1236</a> roku.", "Brian": "<b>Brajan</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_angielski\" target=\"_blank\" rel=\"noopener noreferrer\">ang.</a>&#160;<em>Brian</em>, <i>Bryan</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Celtowie\" target=\"_blank\" rel=\"noopener noreferrer\">celtyckiego</a>, wywodzące się najprawdopodobniej od słów <i>bruaich</i> „wzgórze”, <i>brigh</i> „wysoki”; „szlachetnie urodzony” lub <i>bri</i> „silny”. Do Polski trafiło z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_angielski\" target=\"_blank\" rel=\"noopener noreferrer\">języka angielskiego</a> i zaczęło być nadawane częściej dopiero w latach 90. XX wieku. Popularne jest w krajach anglosaskich, gdzie funkcjonuje zarówno jako samodzielne imię, jak i jako forma <a href=\"https://pl.wikipedia.org/wiki/Zdrobnienie\" target=\"_blank\" rel=\"noopener noreferrer\">zdrobniała</a> od <a href=\"https://pl.wikipedia.org/wiki/Bernard_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Bernarda</a> i <a href=\"https://pl.wikipedia.org/wiki/Barnaba\" target=\"_blank\" rel=\"noopener noreferrer\">Barnaby</a>.", "Bonifacy": "<b>Bonifacy</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>bonum</em> „dobro” i <em>facere</em> „czynić”, czyli oznacza czyniącego dobro.", "Bazyli": "<b>Bazyli</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">późnogreckiego</a>. Pochodzi ono od przymiotnika „królewski, cesarski” (<i>basíleios</i>, od <a href=\"https://pl.wikipedia.org/wiki/II_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">II wieku</a> wymawiane <i>basílios</i>), od rzeczownika <i>basileus</i> – „król, wódz, cesarz”. Jego formą oboczną jest Bazyliusz, a żeńskim odpowiednikiem – <a href=\"https://pl.wikipedia.org/wiki/Bazyla\" target=\"_blank\" rel=\"noopener noreferrer\">Bazyla</a>.", "Bożydar": "<b>Bożydar</b>, <b>Bożdar</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie złożone z członów <i>Boż(y)-</i> („Boga”, ale pierwotnie „losu, doli, szczęścia”) i <i>-dar</i> („upominek, dar, ofiara”). Być może oznaczało „tego, kto jest darem losu”. Imię to (wraz z <a href=\"https://pl.wikipedia.org/wiki/Bogodar\" target=\"_blank\" rel=\"noopener noreferrer\">Bogodarem</a>) uważa się za równoważnik znaczeniowy imienia <i>Adeodat</i> (łacińskiego <i>Adeodatus</i>), czy greckiego <a href=\"https://pl.wikipedia.org/wiki/Teodor\" target=\"_blank\" rel=\"noopener noreferrer\">Teodor</a> lub <a href=\"https://pl.wikipedia.org/wiki/Bogdan\" target=\"_blank\" rel=\"noopener noreferrer\">Bogdan</a>, a zatem Bożydar obchodzi imieniny w dniach wspomnienia św. Adeodatów, których jest kilku.", "Bahadur": "Za historykami <a href=\"https://pl.wikipedia.org/wiki/Chiny\" target=\"_blank\" rel=\"noopener noreferrer\">chińskiej</a> <a href=\"https://pl.wikipedia.org/wiki/Dynastia_Sui\" target=\"_blank\" rel=\"noopener noreferrer\">dynastii Sui</a> można przyjąć, że tytuł ten był używany przez ludy stepowe żyjące na północ i zachód od <a href=\"https://pl.wikipedia.org/wiki/Chiny\" target=\"_blank\" rel=\"noopener noreferrer\">Chin</a> co najmniej od <a href=\"https://pl.wikipedia.org/wiki/VII_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">VII wieku</a>. W <a href=\"https://pl.wikipedia.org/wiki/Pierwszy_kaganat_turecki\" target=\"_blank\" rel=\"noopener noreferrer\">kaganacie starotureckim</a> przyjmował on formę <i>batur</i>, <a href=\"https://pl.wikipedia.org/wiki/Protobu%C5%82garzy\" target=\"_blank\" rel=\"noopener noreferrer\">Protobułgarzy</a> w <a href=\"https://pl.wikipedia.org/wiki/IX_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">IX wieku</a> używali formy <i>bagatur</i>. <a href=\"https://pl.wikipedia.org/wiki/Czyngis-chan\" target=\"_blank\" rel=\"noopener noreferrer\">Czyngis-chan</a> (w którego czasach występował on w formach <i>bagatur</i> i <i>baatur</i>) nadał go jako oficjalny tytuł honorowy około tysiącu osób ze swojej armii, które chciał szczególnie wyróżnić za odwagę lub wierną służbę. W analogiczny sposób nadawali go władcy państw powstałych po rozpadzie <a href=\"https://pl.wikipedia.org/wiki/Imperium_mongolskie\" target=\"_blank\" rel=\"noopener noreferrer\">imperium mongolskiego</a>, w tym także <a href=\"https://pl.wikipedia.org/wiki/Wielcy_Mogo%C5%82owie\" target=\"_blank\" rel=\"noopener noreferrer\">Wielcy Mogołowie</a>. Od czasów <a href=\"https://pl.wikipedia.org/wiki/Ilchanidzi\" target=\"_blank\" rel=\"noopener noreferrer\">ilchana</a> <a href=\"https://pl.wikipedia.org/wiki/Abu_Sa%E2%80%99id\" target=\"_blank\" rel=\"noopener noreferrer\">Abu Sa’ida</a> (<a href=\"https://pl.wikipedia.org/wiki/1317\" target=\"_blank\" rel=\"noopener noreferrer\">1317</a>–<a href=\"https://pl.wikipedia.org/wiki/1335\" target=\"_blank\" rel=\"noopener noreferrer\">1335</a>) tytułu <i>bahadur</i> używano także jako części tytulatury władcy - postępowali tak <a href=\"https://pl.wikipedia.org/wiki/D%C5%BCalajirydzi\" target=\"_blank\" rel=\"noopener noreferrer\">Dżalajirydzi</a>, <a href=\"https://pl.wikipedia.org/wiki/Timurydzi\" target=\"_blank\" rel=\"noopener noreferrer\">Timurydzi</a>, <a href=\"https://pl.wikipedia.org/wiki/Kara_Kojunlu\" target=\"_blank\" rel=\"noopener noreferrer\">Kara Kojunlu</a>, <a href=\"https://pl.wikipedia.org/wiki/Ak_Kojunlu\" target=\"_blank\" rel=\"noopener noreferrer\">Ak Kojunlu</a>, Wielcy Mogołowie, a w szczególności władcy państw <a href=\"https://pl.wikipedia.org/wiki/Uzbecy\" target=\"_blank\" rel=\"noopener noreferrer\">uzbeckich</a>. Od tego tytułu wywodzi się <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_polski\" target=\"_blank\" rel=\"noopener noreferrer\">polski</a> termin <a href=\"https://pl.wikipedia.org/wiki/Bohater\" target=\"_blank\" rel=\"noopener noreferrer\">bohater</a>.", "Benon": "<b>Benon</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, powstałe jako zdrobnienie <i>Bennon</i> od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a> <i>Bernhard </i> (<a href=\"https://pl.wikipedia.org/wiki/Bernard_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Bernard</a>). W Polsce jest to prawdopodobnie skrót <i>Bień</i> od <a href=\"https://pl.wikipedia.org/wiki/Benedykt\" target=\"_blank\" rel=\"noopener noreferrer\">imienia Benedykt</a>.", "Baltazar": "<b>Baltazar</b> – biblijny zapis akadyjskiego imienia <i>Bēl-šar-ușur</i> (tłum. „(boże) <a href=\"https://pl.wikipedia.org/wiki/Bel_(b%C3%B3stwo)\" target=\"_blank\" rel=\"noopener noreferrer\">Belu</a> króla strzeż!”), noszonego przez syna babilońskiego króla <a href=\"https://pl.wikipedia.org/wiki/Nabonid\" target=\"_blank\" rel=\"noopener noreferrer\">Nabonida</a> (biblijny <a href=\"https://pl.wikipedia.org/wiki/Baltazar_(babilo%C5%84ski_ksi%C4%85%C5%BC%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Baltazar</a>). Imię Baltazar pochodzi od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a> <i>basileus</i> i oznaczało króla.", "Barnaba": "<b>Barnaba</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_aramejski\" target=\"_blank\" rel=\"noopener noreferrer\">aramejskiego</a>. Wywodzi się od <i>Bar-nebuch</i> i oznacza syna pocieszenia, syna proroctwa.", "Bonawentura": "<b>Bonawentura</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_w%C5%82oski\" target=\"_blank\" rel=\"noopener noreferrer\">włoskiego</a>, prawdopodobnie sztuczne imię klasztorne. Wywodzi się od słów <i>bona vantura</i> oznaczającego „dobry los”. Imię pierwszy raz użyte przez <a href=\"https://pl.wikipedia.org/wiki/%C5%9Awi%C4%99ty_Bonawentura\" target=\"_blank\" rel=\"noopener noreferrer\">św. Bonawenturę</a>, ucznia <a href=\"https://pl.wikipedia.org/wiki/Franciszek_z_Asy%C5%BCu\" target=\"_blank\" rel=\"noopener noreferrer\">św. Franciszka z Asyżu</a>. Jedno z rzadkich w <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_polski\" target=\"_blank\" rel=\"noopener noreferrer\">języku polskim</a> imion męskich zakończone na -a. (m.in. <a href=\"https://pl.wikipedia.org/wiki/Barnaba\" target=\"_blank\" rel=\"noopener noreferrer\">Barnaba</a>, <a href=\"https://pl.wikipedia.org/wiki/Juda_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Juda</a>). Ze względu na końcówkę <i>-a</i> imię bywa błędnie postrzegane jako imię żeńskie.", "Bazyl": "<b>Bazyli</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">późnogreckiego</a>. Pochodzi ono od przymiotnika „królewski, cesarski” (<i>basíleios</i>, od <a href=\"https://pl.wikipedia.org/wiki/II_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">II wieku</a> wymawiane <i>basílios</i>), od rzeczownika <i>basileus</i> – „król, wódz, cesarz”. Jego formą oboczną jest Bazyliusz, a żeńskim odpowiednikiem – <a href=\"https://pl.wikipedia.org/wiki/Bazyla\" target=\"_blank\" rel=\"noopener noreferrer\">Bazyla</a>.", "Bertold": "<b>Bertold</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>. Wywodzi się od starogermańskich słów <i>berath</i> „światły” i <i>wald</i> – „władca” i oznaczającego „światły władca”.", "Borysław": "<b>Borzysław</b> – męskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię pochodzenia słowiańskiego</a>. Wywodzi się od słów oznaczających „ten, który zdobywa sławę w boju”. Rosyjskim odpowiednikiem tego imienia jest <i>Borisław (Борислав)</i>.", "Bojan": "<b>Bojan</b> – <a href=\"https://pl.wikipedia.org/wiki/Derywat_(j%C4%99zykoznawstwo)\" target=\"_blank\" rel=\"noopener noreferrer\">derywat</a> od <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">staropolskich imion</a> męskich z członem <i>-boj</i> – oznaczającym „bój, bicie, walkę” – takich jak <a href=\"https://pl.wikipedia.org/wiki/Budziboj\" target=\"_blank\" rel=\"noopener noreferrer\">Budziboj</a> lub <a href=\"https://pl.wikipedia.org/wiki/Przyboj\" target=\"_blank\" rel=\"noopener noreferrer\">Przyboj</a>.", "Brendan": "<b>Brendan</b>, <b>Brandon</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_celtyckie\" target=\"_blank\" rel=\"noopener noreferrer\">celtyckiego</a> wywodzące się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_walijski\" target=\"_blank\" rel=\"noopener noreferrer\">walijskiego</a> <i>breenhin</i>, 'książę'. Patronem tego imienia jest św. <a href=\"https://pl.wikipedia.org/wiki/Brendan_%C5%BBeglarz\" target=\"_blank\" rel=\"noopener noreferrer\">Brendan Żeglarz</a>, VI-wieczny mnich i eremita irlandzki, który według legendy w poszukiwaniu odosobnienia wyruszył łodzią na ocean Atlantycki.", "Bernardyn": "<b>Bernardyn</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia germańskiego, pierwotnie powstałe jako zdrobnienie imienia <a href=\"https://pl.wikipedia.org/wiki/Bernard_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Bernard</a> na gruncie łacińsko-włoskim. W Polsce notowane od 1465 r., w formach <i>Bernardyn</i>, <i>Barnardyn</i>, <i>Bernhardyn</i>, <i>Biernardyn</i>, <i>Bernardinus</i>, <i>Barnardinus</i>, <i>Bernhardinus</i>, <i>Biernardinus</i>, z formami pochodnymi Bernasz i Barnasz. Od tego imienia wywodzą się ludowe nazwiska <i>Bernady</i> i <i>Barnady</i>. Istnieje piętnastu świętych lub błogosławionych o tym imieniu.", "Bertrand": "<b>Bertrand</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>. Wywodzi się od słów <i>berath</i> \"światły\", \"jasny\" i <i>hramm</i> \"kruk\". Znaczy \"biały kruk\". Innym jego wariantem jest <b><a href=\"https://pl.wikipedia.org/wiki/Bertram_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Bertram</a></b>. Patronem imienia jest m.in. św. Bertrand z Comminges.", "Bjorn": "<b>Ursus</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od wyrazu <i>ursus</i> oznaczającego „niedźwiedź”. W językach skandynawskich jego odpowiednikiem jest <i>Björn</i>, który cieszy się sporą popularnością. Najwięcej osób nosi to imię w <a href=\"https://pl.wikipedia.org/wiki/Szwecja\" target=\"_blank\" rel=\"noopener noreferrer\">Szwecji</a> (61 099 2006). W <a href=\"https://pl.wikipedia.org/wiki/Norwegia\" target=\"_blank\" rel=\"noopener noreferrer\">Norwegii</a> imię to jest trzecim co do popularności imieniem (nosi je 40 537 osób). Wśród patronów tego imienia – <a href=\"https://pl.wikipedia.org/wiki/Ursus_i_Wiktor\" target=\"_blank\" rel=\"noopener noreferrer\">św. Ursus</a>, męczennik i św. Ursus, biskup (<a href=\"https://pl.wikipedia.org/wiki/VI_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">VI wiek</a>).", "Bülent": "<b>Bülent</b> – tureckie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, oznaczające dosłownie kogoś, kto jest wysoki, wielki, potężny.", "Baruch": "<b>Baruch</b>, <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia hebrajskiego (ברוך), oznaczające <i>błogosławiony</i>.", "Bharat": "Nazwa „Indie”, której odpowiedniki używane są w wielu językach, pochodzi z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_perski\" target=\"_blank\" rel=\"noopener noreferrer\">języka perskiego</a>. <a href=\"https://pl.wikipedia.org/wiki/Persowie\" target=\"_blank\" rel=\"noopener noreferrer\">Persowie</a>, którzy panowali nad zachodnimi rejonami Indii (dolina Indusu, ob. głównie <a href=\"https://pl.wikipedia.org/wiki/Pakistan\" target=\"_blank\" rel=\"noopener noreferrer\">Pakistan</a>), nazywali je <i>Hindu</i>, od nazwy rzeki <a href=\"https://pl.wikipedia.org/wiki/Indus\" target=\"_blank\" rel=\"noopener noreferrer\">Indus</a> (w sanskrycie <i>Sindhu</i>, po persku <i>Hindu</i>). Nazwy Indii w językach europejskich wywodzą się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">języka greckiego</a>, w którym inicjalne h słowa perskiego zanikło: stąd Grecy nazywali mieszkańców Indii <i>Indoi</i>, sam zaś kraj <i>India</i>. W islamskim kręgu kulturowym upowszechniła się natomiast nazwa <i>Hindostan</i>.", "Benito": "<b>Benedykt</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od słowa <i>benedictus</i>, oznaczającego „tego, o którym się dobrze mówi”; „tego, któremu się dobrze życzy”. Znanym imiennikiem był <a href=\"https://pl.wikipedia.org/wiki/Benedykt_z_Nursji\" target=\"_blank\" rel=\"noopener noreferrer\">Benedykt z Nursji</a>, założyciel <a href=\"https://pl.wikipedia.org/wiki/Benedyktyni\" target=\"_blank\" rel=\"noopener noreferrer\">opactwa benedyktyńskiego</a> na <a href=\"https://pl.wikipedia.org/wiki/Monte_Cassino\" target=\"_blank\" rel=\"noopener noreferrer\">Monte Cassino</a>, i <a href=\"https://pl.wikipedia.org/wiki/Baruch_Spinoza\" target=\"_blank\" rel=\"noopener noreferrer\">Spinoza</a>.", "Besarion": "<b>Besarion</b> (<a href=\"https://pl.wikipedia.org/wiki/Greka\" target=\"_blank\" rel=\"noopener noreferrer\">grec.</a> <i>Βησσαρίων</i> – leśny) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia greckiego oznaczające pochodzący z miasta Besaro. W niektórych krajach, m.in. w <a href=\"https://pl.wikipedia.org/wiki/Rosja\" target=\"_blank\" rel=\"noopener noreferrer\">Rosji</a> występuje w <a href=\"https://pl.wikipedia.org/wiki/Greka_bizantyjska\" target=\"_blank\" rel=\"noopener noreferrer\">bizantyjskiej</a> formie <b>Wissarion</b>.", "Bertram": "<b>Bertram</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>. Wywodzi się od słów <i>berath</i> „światły”, „jasny” i <i>hramm</i> „kruk”. Znaczy „biały kruk”. Innym jego wariantem jest <b><a href=\"https://pl.wikipedia.org/wiki/Bertrand_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Bertrand</a></b>.", "Bożysław": "<b>Borzysław</b> – męskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię pochodzenia słowiańskiego</a>. Wywodzi się od słów oznaczających „ten, który zdobywa sławę w boju”. Rosyjskim odpowiednikiem tego imienia jest <i>Borisław (Борислав)</i>.", "Bolko": "<b>Bolesław</b> (<i>bole(j)</i> + <i>sław</i> – „bardziej sławny”) – <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">słowiańskie imię</a> męskie. Dawniej zapisywane również w formie skróconej Bosław lub Bolko. Imię dynastyczne w polskiej dynastii <a href=\"https://pl.wikipedia.org/wiki/Piastowie\" target=\"_blank\" rel=\"noopener noreferrer\">Piastów</a> oraz czeskiej <a href=\"https://pl.wikipedia.org/wiki/Przemy%C5%9Blidzi\" target=\"_blank\" rel=\"noopener noreferrer\">Przemyślidów</a>. Do dynastii piastowskiej zostało zapożyczone od <a href=\"https://pl.wikipedia.org/wiki/Przemy%C5%9Blidzi\" target=\"_blank\" rel=\"noopener noreferrer\">Przemyślidów</a> poprzez dziedziczenie po linii żeńskiej (imię kognacyjne). Ostatnim jego piastowskim przedstawicielem był Piast mazowiecki <a href=\"https://pl.wikipedia.org/wiki/Boles%C5%82aw_V_warszawski\" target=\"_blank\" rel=\"noopener noreferrer\">Bolesław V, książę warszawski</a> (XV w.).", "Béla": "<b>Béla</b> – węgierskie imię utożsamiane z <a href=\"https://pl.wikipedia.org/wiki/Adalbert\" target=\"_blank\" rel=\"noopener noreferrer\">Adalbertem</a>, poza Węgrami pisane czasem jako Bela. Imieniny obchodzi na Węgrzech w dniu <a href=\"https://pl.wikipedia.org/wiki/23_kwietnia\" target=\"_blank\" rel=\"noopener noreferrer\">23 kwietnia</a>, poza – <a href=\"https://pl.wikipedia.org/wiki/3_maja\" target=\"_blank\" rel=\"noopener noreferrer\">3 maja</a>.", "Bahram": "<b>Bahram</b> (również: Wahram, Warhran <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_pahlawi\" target=\"_blank\" rel=\"noopener noreferrer\">pahl.</a> Whrmzd <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_awestyjski\" target=\"_blank\" rel=\"noopener noreferrer\">awest</a>. <a href=\"https://pl.wikipedia.org/wiki/Weretragna\" target=\"_blank\" rel=\"noopener noreferrer\">Weretragna</a>, <a href=\"https://pl.wikipedia.org/wiki/Wedy\" target=\"_blank\" rel=\"noopener noreferrer\">wedyjski</a> Wrtrahan) – <a href=\"https://pl.wikipedia.org/wiki/Epitet\" target=\"_blank\" rel=\"noopener noreferrer\">epitet</a> <a href=\"https://pl.wikipedia.org/wiki/Indra\" target=\"_blank\" rel=\"noopener noreferrer\">Indry</a>, oznaczający zabójcę smoka Wrtry, jazata zwycięstwa, niszczyciel zła, boża broń, pomocnik jednego z <a href=\"https://pl.wikipedia.org/wiki/Amszaspandowie\" target=\"_blank\" rel=\"noopener noreferrer\">Amszaspandów</a> – <a href=\"https://pl.wikipedia.org/wiki/Ardibeheszt\" target=\"_blank\" rel=\"noopener noreferrer\">Arta Wahiszta</a>, strażnik prawdy na usługach <a href=\"https://pl.wikipedia.org/wiki/Mitra_(mitologia)\" target=\"_blank\" rel=\"noopener noreferrer\">Mitry</a> i strażnik ognia.", "Barnim": "<b>Barnim</b> – <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">męskie imię pochodzenia słowiańskiego</a>. Było spotykane wśród <a href=\"https://pl.wikipedia.org/wiki/Ksi%C4%85%C5%BC%C4%99ta_pomorscy\" target=\"_blank\" rel=\"noopener noreferrer\">książąt pomorskich</a>.", "Boguchwał": "<b>Boguchwał</b>, <b>Bogchwał</b>, <b>Bochwał</b>, <b>Boguchał</b>, <b>Bogufał</b>, <b>Bogofał</b>, <b>Bogfał</b>, <b>Bofał</b> – <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">staropolskie imię</a> męskie, złożone z członu <i>Bogu-</i> (\"Bóg\", ale pierwotnie \"los, dola, szczęście\") i <i>-chwał</i> (\"chwalić, sławić, dziękować\"). Prawdopodobnie oznaczało \"tego, który sławi szczęście\", późn. \"tego, który sławi Boga\". Zob. też <a href=\"https://pl.wikipedia.org/wiki/Chwalibog\" target=\"_blank\" rel=\"noopener noreferrer\">Chwalibog</a>, <a href=\"https://pl.wikipedia.org/wiki/Chwalibog\" target=\"_blank\" rel=\"noopener noreferrer\">Chwaliboż</a>, <a href=\"https://pl.wikipedia.org/wiki/Chwalibog\" target=\"_blank\" rel=\"noopener noreferrer\">Falibog</a>, <a href=\"https://pl.wikipedia.org/wiki/Chwalibog\" target=\"_blank\" rel=\"noopener noreferrer\">Faliboż</a>.", "Bolebor": "<b>Bolebor</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie. Składa się z członu <i>Bole-</i> (\"więcej\") i <i>-bor</i> (\"walka\", \"walczyć, zmagać się\"). Imię to mogło oznaczać \"tego, kto więcej walczy\".", "Beat": "<b>Beat</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od słowa <i>beatus</i> – <a href=\"https://pl.wikipedia.org/wiki/B%C5%82ogos%C5%82awiony\" target=\"_blank\" rel=\"noopener noreferrer\">błogosławiony</a>. Zbliżone w znaczeniu do imion <a href=\"https://pl.wikipedia.org/wiki/Feliks\" target=\"_blank\" rel=\"noopener noreferrer\">Feliks</a> i <a href=\"https://pl.wikipedia.org/wiki/Fortunat\" target=\"_blank\" rel=\"noopener noreferrer\">Fortunat</a>.", "Bratumił": "<b>Bratumił</b>, <b>Bratomił</b>, <b>Bratmił</b>, (zniem.) <b>Bretomił</b>, <b>Bretmił</b> – <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">staropolskie imię</a> męskie, złożone z członów <i>Bratu-</i> (\"bratu\", \"członkowi wspólnoty rodowej\", \"człowiekowi bliskiemu\") i <i>-mił</i> (\"miły\"). Znaczenie imienia: \"miły swoim bliskim\".", "Beau": "<b>Beau</b> (właściwie Christopher John Trevor Midgley), ur. maj <a href=\"https://pl.wikipedia.org/wiki/1946\" target=\"_blank\" rel=\"noopener noreferrer\">1946</a> w <a href=\"https://pl.wikipedia.org/wiki/Leeds\" target=\"_blank\" rel=\"noopener noreferrer\">Leeds</a>, <a href=\"https://pl.wikipedia.org/wiki/Wielka_Brytania\" target=\"_blank\" rel=\"noopener noreferrer\">Wielka Brytania</a> – brytyjski muzyk <a href=\"https://pl.wikipedia.org/wiki/Muzyka_folkowa\" target=\"_blank\" rel=\"noopener noreferrer\">folkowy</a> specjalizujący się w grze na <a href=\"https://pl.wikipedia.org/wiki/Gitara_dwunastostrunowa\" target=\"_blank\" rel=\"noopener noreferrer\">dwunastostrunowej gitarze</a>. Pseudonim Beau <a href=\"https://pl.wikipedia.org/wiki/Wymowa\" target=\"_blank\" rel=\"noopener noreferrer\">wym.</a> <i>bou</i>) w <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_polski\" target=\"_blank\" rel=\"noopener noreferrer\">jęz. pol.</a> oznacza „eleganta”.", "Boromeusz": "<b>Boromeusz</b> – imię męskie, pochodzące od nazwiska <a href=\"https://pl.wikipedia.org/wiki/Karol_Boromeusz\" target=\"_blank\" rel=\"noopener noreferrer\">św. Karola Boromeusza</a>. Żeński odpowiednik to <a href=\"https://pl.wikipedia.org/wiki/Boromea\" target=\"_blank\" rel=\"noopener noreferrer\">Boromea</a>.", "Benicjusz": "<b>Benicjusz</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzące od włoskiego <a href=\"https://pl.wikipedia.org/wiki/Serwici\" target=\"_blank\" rel=\"noopener noreferrer\">serwity</a>, św. <a href=\"https://pl.wikipedia.org/wiki/Filip_Benicjusz\" target=\"_blank\" rel=\"noopener noreferrer\">Filipa Benicjusza</a> (wł. <i>Benizi</i>). <a href=\"https://pl.wikipedia.org/wiki/Imieniny\" target=\"_blank\" rel=\"noopener noreferrer\">Imieniny</a> obchodzi <a href=\"https://pl.wikipedia.org/wiki/23_sierpnia\" target=\"_blank\" rel=\"noopener noreferrer\">23 sierpnia</a>.", "Bożymir": "<b>Borzymir</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, złożone z członów <i>Borzy-</i> (\"walczyć\", \"walka\") oraz <i>-mir</i> (\"pokój\"). Mogło oznaczać \"ten, który walczy o pokój\".", "Bończa": "<b>Bonifacy</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>bonum</em> „dobro” i <em>facere</em> „czynić”, czyli oznacza czyniącego dobro.", "Bronimir": "<b>Bronimir</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, złożone z członów <i>Broni-</i> (\"bronić, strzec\") i <i>-mir</i> (\"pokój, spokój, dobro\"). Zapisy takiego imienia nie przechowały się w dokumentach staropolskich, jednak o jego istnieniu może świadczyć przechowanie się w nazwach miejscowych – takich jak <a href=\"https://pl.wikipedia.org/wiki/Bromierz\" target=\"_blank\" rel=\"noopener noreferrer\">Bromierz</a>, <a href=\"https://pl.wikipedia.org/wiki/Bromierzyk\" target=\"_blank\" rel=\"noopener noreferrer\">Bromierzyk</a> – formy <b>Bromir</b>, która mogła stanowić jego formę skróconą.", "Baldwin": "<b>Baldwin</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>, złożone z członów <i>Bald-</i> – „śmiałość, odwaga” i <i>wini</i> – „przyjaciel, miłośnik”. Mogło ono zatem oznaczać „miłośnika odwagi”, czy też po prostu „śmiałego, odważnego”. Baldwin był jednym z imion rodowych hrabiów z <a href=\"https://pl.wikipedia.org/wiki/Bouillon_(Belgia)\" target=\"_blank\" rel=\"noopener noreferrer\">Bouillon</a> i <a href=\"https://pl.wikipedia.org/wiki/W%C5%82adcy_Flandrii#Dynastia_flandryjska\" target=\"_blank\" rel=\"noopener noreferrer\">hrabiów flandryjskich</a>. W Polsce spotykane po raz pierwszy na przełomie <a href=\"https://pl.wikipedia.org/wiki/XI_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XI</a> i <a href=\"https://pl.wikipedia.org/wiki/XII_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XII wieku</a> jako imię <a href=\"https://pl.wikipedia.org/wiki/Baldwin_(biskup_krakowski)\" target=\"_blank\" rel=\"noopener noreferrer\">Baldwina, biskupa krakowskiego</a>. Pojawiało się także w formach Baldewin, Beldwin, Balwin, oraz <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">lat.</a> Baldwinus, Baldewinus, Balduwinus, Balwinus i <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_francuski\" target=\"_blank\" rel=\"noopener noreferrer\">fr.</a>-lat. Bauduinus. Niektóre możliwe staropolskie zdrobnienia to: Bal, Bala (masc.), Balich.", "Bronisz": "<b>Bronisław</b>, <b>Bronsław</b>, <b>Barnisław</b>, (zniem.) <b>Brunisław</b>, <b>Brosław</b> – męskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię pochodzenia słowiańskiego</a>.", "Bogodar": "Imię to (wraz z <a href=\"https://pl.wikipedia.org/wiki/Bo%C5%BCydar_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Bożydarem</a>) uważa się za równoważnik znaczeniowy imienia <i><b>Adeodat</b></i>, a zatem Bogodar obchodzi imieniny w dniach wspomnienia św. Adeodatów.", "Bento": "Pierwsze wzmianki o bentō pochodzą z V wieku n.e., kiedy to Japończycy wyruszali polować lub łowić ryby z dala od swoich domostw. Zabierali wtedy ze sobą podsuszany <a href=\"https://pl.wikipedia.org/wiki/Ry%C5%BC\" target=\"_blank\" rel=\"noopener noreferrer\">ryż</a>, który po wymieszaniu z wodą rolowano w małe porcje.", "Baraka": "<i>Baraka</i> to starodawne słowo <a href=\"https://pl.wikipedia.org/wiki/Sufizm\" target=\"_blank\" rel=\"noopener noreferrer\">sufich</a>. Oznacza błogosławieństwo, esencję życia, od której rozpoczyna się ewolucja.", "B": "<b>B</b> (wymowa: <i>be</i>, <a href=\"https://pl.wikipedia.org/wiki/Minusku%C5%82a\" target=\"_blank\" rel=\"noopener noreferrer\">minuskuła</a>: <b>b</b>) – druga litera <a href=\"https://pl.wikipedia.org/wiki/Alfabet_%C5%82aci%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">alfabetu łacińskiego</a>, trzecia litera alfabetu polskiego. Oznacza w danym języku zwykle <a href=\"https://pl.wikipedia.org/wiki/Sp%C3%B3%C5%82g%C5%82oska_zwarta_dwuwargowa_d%C5%BAwi%C4%99czna\" target=\"_blank\" rel=\"noopener noreferrer\">spółgłoskę zwartą dwuwargową dźwięczną</a>, np. [<a href=\"https://pl.wikipedia.org/wiki/Sp%C3%B3%C5%82g%C5%82oska_zwarta_dwuwargowa_d%C5%BAwi%C4%99czna\" target=\"_blank\" rel=\"noopener noreferrer\">b</a>].", "Borzysław": "<b>Borzysław</b> – męskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię pochodzenia słowiańskiego</a>. Wywodzi się od słów oznaczających „ten, który zdobywa sławę w boju”. Rosyjskim odpowiednikiem tego imienia jest <i>Borisław (Борислав)</i>.", "Bogudar": "Imię to (wraz z <a href=\"https://pl.wikipedia.org/wiki/Bo%C5%BCydar_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Bożydarem</a>) uważa się za równoważnik znaczeniowy imienia <i><b>Adeodat</b></i>, a zatem Bogodar obchodzi imieniny w dniach wspomnienia św. Adeodatów.", "Bogumir": "<b>Bogumił</b>, <b>Bogomił</b>, <b>Bogmił</b>, <b>Bogomieł</b>, <b>Bogmieł</b>, <b>Bogumieł</b> – <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">staropolskie imię</a> męskie. Wywodzi się ze złożenia członów: <i>Bog-</i> („Bóg”, ale pierwotnie w znaczeniu „los, dola, szczęście”) oraz <i>-mił</i> („miły”). Oznacza więc: „miły Bogu” (lecz uprzednio mogło znaczyć „ten, któremu los sprzyja”). <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">Imiona słowiańskie</a> ze składnikami <i>Bog-</i> (np. Bogumił czy Bogusław) mogą być także słowiańskim naśladownictwem irańskich imion używanych w czasach od <a href=\"https://pl.wikipedia.org/wiki/VI_wiek_p.n.e.\" target=\"_blank\" rel=\"noopener noreferrer\">VI</a> do <a href=\"https://pl.wikipedia.org/wiki/IV_wiek_p.n.e.\" target=\"_blank\" rel=\"noopener noreferrer\">IV wieku p.n.e.</a>, takich jak Bagafarna („mający sławę od Boga”).", "Bazar": "Targowiska mogą mieć charakter spontaniczny lub zorganizowany. W tym drugim przypadku teren przeznaczony do handlu może mieć wyznaczone płatne stanowiska dla osób oferujących swoje towary. Targowiska umożliwiają swobodny, bezpośredni kontakt handlowca z klientem i bezpośrednie negocjowanie <a href=\"https://pl.wikipedia.org/wiki/Cena_(ekonomia)\" target=\"_blank\" rel=\"noopener noreferrer\">ceny</a>. W pewnym sensie rozwinięciem idei targowiska są <a href=\"https://pl.wikipedia.org/wiki/Gie%C5%82da\" target=\"_blank\" rel=\"noopener noreferrer\">giełdy</a>, które od targowisk różnią się w zasadzie tylko bardziej sformalizowanym stylem negocjowania cen.", "Beda": "<b>Beda</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie łączone z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskim</a> <i>beadu</i>, <i>beado</i> — \"wojna, walka\". Istnieje trzech świętych o tym imieniu, wśród nich najbardziej znanym jest <a href=\"https://pl.wikipedia.org/wiki/Beda_Czcigodny\" target=\"_blank\" rel=\"noopener noreferrer\">Beda Czcigodny</a>, angielski historyk, uczony i <a href=\"https://pl.wikipedia.org/wiki/Doktor_Ko%C5%9Bcio%C5%82a\" target=\"_blank\" rel=\"noopener noreferrer\">doktor Kościoła</a> z <a href=\"https://pl.wikipedia.org/wiki/VIII_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">VIII wieku</a>.", "Bueno": "Informacje o tej postaci pochodzą z późnego <i>Vitae</i> zachowanego w rękopisie w <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_walijski\" target=\"_blank\" rel=\"noopener noreferrer\">języku walijskim</a> (datowanego na 1346 r.).", "Bogurad": "<b>Bogurad</b>, <b>Bogured</b> – <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">staropolskie imię</a> męskie złożone z członów <i>Bog-</i> (\"Bóg\", ale pierwotnie \"los, dola, szczęście\") i <i>-rad</i> (\"być zadowolonym, chętnym, cieszyć się\"). Mogło zatem oznaczać \"ten, który jest pozytywnie nastawiony do Boga\" albo \"ten, który cieszy się szczęściem\".", "Budzisław": "<b>Budzisław</b>, Budzsław – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, złożone z członów <i>Budzi-</i> (\"budzić\") i <i>-sław</i> (\"sława\"). Mogło oznaczać \"ten, który zyskuje sławę\". Imię to notowane jest w Polsce od 1136 roku.", "Bada": "<b>bada OS</b> – <a href=\"https://pl.wikipedia.org/wiki/System_operacyjny\" target=\"_blank\" rel=\"noopener noreferrer\">system operacyjny</a> dla <a href=\"https://pl.wikipedia.org/wiki/Telefon_kom%C3%B3rkowy\" target=\"_blank\" rel=\"noopener noreferrer\">telefonów komórkowych</a>. Został stworzony przez firmę <a href=\"https://pl.wikipedia.org/wiki/Samsung\" target=\"_blank\" rel=\"noopener noreferrer\">Samsung</a>, a zaprezentowany w listopadzie 2009. Nazwa <i>bada</i> w tłumaczeniu z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_korea%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">języka koreańskiego</a> oznacza ocean lub morze.", "Borromeo": "<b>Boromeusze</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_w%C5%82oski\" target=\"_blank\" rel=\"noopener noreferrer\">wł.</a> Borromeo) – <a href=\"https://pl.wikipedia.org/wiki/Lombardia\" target=\"_blank\" rel=\"noopener noreferrer\">lombardzko</a>-<a href=\"https://pl.wikipedia.org/wiki/Piemont\" target=\"_blank\" rel=\"noopener noreferrer\">piemoncki</a> <a href=\"https://pl.wikipedia.org/wiki/R%C3%B3d\" target=\"_blank\" rel=\"noopener noreferrer\">ród</a> kupiecki, bankierski i arystokratyczny, z którego wywodziło się wielu <a href=\"https://pl.wikipedia.org/wiki/Kardyna%C5%82\" target=\"_blank\" rel=\"noopener noreferrer\">kardynałów</a>, m.in. św. <a href=\"https://pl.wikipedia.org/wiki/Karol_Boromeusz\" target=\"_blank\" rel=\"noopener noreferrer\">Karol Boromeusz</a> czy <a href=\"https://pl.wikipedia.org/wiki/Federico_Borromeo_(1564%E2%80%931631)\" target=\"_blank\" rel=\"noopener noreferrer\">Fryderyk</a>, uwieczniony w <a href=\"https://pl.wikipedia.org/wiki/Powie%C5%9B%C4%87\" target=\"_blank\" rel=\"noopener noreferrer\">powieści</a> <a href=\"https://pl.wikipedia.org/wiki/Alessandro_Manzoni\" target=\"_blank\" rel=\"noopener noreferrer\">Alessandra Manzoniego</a> pt. <i><a href=\"https://pl.wikipedia.org/wiki/Narzeczeni_(powie%C5%9B%C4%87)\" target=\"_blank\" rel=\"noopener noreferrer\">Narzeczeni</a></i>.", "Bai": "Lud Bai ceni wysoko kolor biały, od którego zresztą wywodzi się jego nazwa. Jego przedstawiciele mówią o sobie <i>Baizi</i>, <i>Baini</i> lub <i>Baihuo</i>, co oznacza „Biały Lud”. Oficjalna chińska nazwa została nadana w 1956 roku.", "Bibian": "<b>Bibian</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie utworzone od <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiej</a> nazwy rodu <i>Vivius</i> i oznaczające \"należący do rodu <i>Vivii</i>\". Patronem tego imienia jest św. Bibian, biskup <a href=\"https://pl.wikipedia.org/wiki/Saintes\" target=\"_blank\" rel=\"noopener noreferrer\">Saintes</a> (<a href=\"https://pl.wikipedia.org/wiki/V_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">V wiek</a>).", "Baja": "<b>Baja</b> lub <b>bay'a</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab</a>. بَيْعَة = „sprzedaż”, „transakcja handlowa”) – <a href=\"https://pl.wikipedia.org/wiki/Islam\" target=\"_blank\" rel=\"noopener noreferrer\">islamska</a> przysięga wierności składana <a href=\"https://pl.wikipedia.org/wiki/Kalif\" target=\"_blank\" rel=\"noopener noreferrer\">kalifowi</a> przez muzułmanów. Odbierający przysięgę kalif zobowiązywał się do przestrzegania przepisów prawa muzułmańskiego, natomiast muzułmanin składający ją uznawał autorytet kalifa i przysięgał mu posłuszeństwo. Muzułmanin składający przysięgę symbolicznie dotykał otwartej dłoni kalifa. Jej złożeniu często towarzyszyła wielka uroczystość. Baję złożyło <a href=\"https://pl.wikipedia.org/wiki/Mahomet\" target=\"_blank\" rel=\"noopener noreferrer\">Mahometowi</a> 1400 muzułmanów w Al-Hudajbiji. <a href=\"https://pl.wikipedia.org/wiki/Mirza_Gulam_Ahmad\" target=\"_blank\" rel=\"noopener noreferrer\">Mirza Gulam Ahmad</a>, założyciel islamskiego ruchu reformatorskiego <a href=\"https://pl.wikipedia.org/wiki/Ahmadijja\" target=\"_blank\" rel=\"noopener noreferrer\">ahmadijja</a>, formalnie rozpoczął swoje panowanie nad islamską gminą od odebrania baji. W czasach przedislamskich pojęcie to oznaczało zakończenie transakcji handlowej wyrażone przez potrząśnięcie dłonią.", "Brahma": "<b>Brahma</b> (<a href=\"https://pl.wikipedia.org/wiki/Pismo_dewanagari\" target=\"_blank\" rel=\"noopener noreferrer\">dewanagari</a> ब्रह्मा, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_tamilski\" target=\"_blank\" rel=\"noopener noreferrer\">tamil.</a>&#160;பிரம்மா) – w <a href=\"https://pl.wikipedia.org/wiki/Hinduizm\" target=\"_blank\" rel=\"noopener noreferrer\">hinduizmie</a> wraz z <a href=\"https://pl.wikipedia.org/wiki/Wisznu\" target=\"_blank\" rel=\"noopener noreferrer\">Wisznu</a> i <a href=\"https://pl.wikipedia.org/wiki/%C5%9Aiwa\" target=\"_blank\" rel=\"noopener noreferrer\">Śiwą</a> tworzy <a href=\"https://pl.wikipedia.org/wiki/Trimurti\" target=\"_blank\" rel=\"noopener noreferrer\">Trimurti</a>. W każdym z niezliczonej ilości <a href=\"https://pl.wikipedia.org/wiki/Wszech%C5%9Bwiat\" target=\"_blank\" rel=\"noopener noreferrer\">wszechświatów</a>, stwarzanych przez <a href=\"https://pl.wikipedia.org/wiki/Mahawisznu\" target=\"_blank\" rel=\"noopener noreferrer\">Mahawisznu</a> Brahma jest pierwszą, śmiertelną, żywą istotą, zrodzoną z formy <i>virat</i> – kwiatu lotosu wyrastającego z jeziora umiejscowionego w pępku <a href=\"https://pl.wikipedia.org/wiki/Garbhodaka%C5%9Baji\" target=\"_blank\" rel=\"noopener noreferrer\">Garbhodakaśaji Wisznu</a>, stąd bierze się jego inne imię <i>Aja</i>.", "Bael": "<b>Bael</b> – w tradycji <a href=\"https://pl.wikipedia.org/wiki/Okultyzm\" target=\"_blank\" rel=\"noopener noreferrer\">okultystycznej</a>, <a href=\"https://pl.wikipedia.org/wiki/Demon\" target=\"_blank\" rel=\"noopener noreferrer\">demon</a>, król <a href=\"https://pl.wikipedia.org/wiki/Piek%C5%82o\" target=\"_blank\" rel=\"noopener noreferrer\">piekła</a> (wschodniej części), znany również pod imieniem <b>Baal</b>. Włada 66 legionami duchów piekielnych. W <i><a href=\"https://pl.wikipedia.org/wiki/Lemegeton\" target=\"_blank\" rel=\"noopener noreferrer\">Lemegetonie</a></i> i <i><a href=\"https://pl.wikipedia.org/wiki/Pseudomonarchia_Daemonum\" target=\"_blank\" rel=\"noopener noreferrer\">Pseudomonarchii Daemonum</a></i> jest pierwszym <a href=\"https://pl.wikipedia.org/wiki/Duch_(spirytyzm)\" target=\"_blank\" rel=\"noopener noreferrer\">duchem</a>.", "Bunta": "<b>Bunta</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;ぶんた, ブンタ) – <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">męskie imię japońskie</a>.", "Bedgost": "<b>Bdzigost</b> [bˈd͡ʑigɔst﻿&#65279;<a href=\"https://www.wikidata.org/wiki/Q8615234#sitelinks-wikipedia\" target=\"_blank\" rel=\"noopener noreferrer\">(inne języki)</a>], <b>Bedgost</b> [ˈbɛdgɔst&#65279;<a href=\"https://www.wikidata.org/wiki/Q8615234#sitelinks-wikipedia\" target=\"_blank\" rel=\"noopener noreferrer\">(inne języki)</a>] – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie. Składa się z członu <i>Bdzi-</i> (\"powoduje, że czuwa\", por. <i>budzić</i>) i <i>gost-</i> (\"gościć\", \"gość\"). Mogło zatem oznaczać \"budzący gości\".", "Bhumi": "<b>Bhūmi</b> (<a href=\"https://pl.wikipedia.org/wiki/Sanskryt\" target=\"_blank\" rel=\"noopener noreferrer\">skt.</a> <i>bhūmi</i>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_tybeta%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">tyb.</a> <i>byang chub sems dpa'i sa</i>, poziomy oświeconej istoty) – w tradycji <a href=\"https://pl.wikipedia.org/wiki/Mahajana\" target=\"_blank\" rel=\"noopener noreferrer\">mahajany</a> oznacza dziesięć poziomów <a href=\"https://pl.wikipedia.org/wiki/Bodhisattwa\" target=\"_blank\" rel=\"noopener noreferrer\">Bodhisattwy</a> na ścieżce przebudzenia. Sanskrycki termin bhūmi oznacza dosłownie \"podstawę\". Każdy poziom oznacza etap urzeczywistnienia i służy jako podstawa dla następnego poziomu. Każdy poziom oznacza określony postęp w treningu i towarzyszy mu konsekwentny wzrost mocy i mądrości.", "Benignus": "<b>Benigny</b>, <b>Benignus</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od słowa „uprzejmy”, „przyjazny”. Patronem imienia jest m.in. <a href=\"https://pl.wikipedia.org/wiki/Benigny_z_Dijon\" target=\"_blank\" rel=\"noopener noreferrer\">św. Benigny z Dijon</a>, męczennik z II wieku.", "Budziwoj": "<b>Budziwoj</b>, <b>Budźwoj</b> – <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">staropolskie imię</a> męskie, złożone z członów <i>Budzi-</i>, <i>Budź-</i> (\"budzić\") i <i>-woj</i> (\"wojownik\"). Oznacza \"tego, który budzi wojowników, wzywa do walki\".", "Bromir": "<b>Bronimir</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, złożone z członów <i>Broni-</i> (\"bronić, strzec\") i <i>-mir</i> (\"pokój, spokój, dobro\"). Zapisy takiego imienia nie przechowały się w dokumentach staropolskich, jednak o jego istnieniu może świadczyć przechowanie się w nazwach miejscowych – takich jak <a href=\"https://pl.wikipedia.org/wiki/Bromierz\" target=\"_blank\" rel=\"noopener noreferrer\">Bromierz</a>, <a href=\"https://pl.wikipedia.org/wiki/Bromierzyk\" target=\"_blank\" rel=\"noopener noreferrer\">Bromierzyk</a> – formy <b>Bromir</b>, która mogła stanowić jego formę skróconą.", "Behram": "<b>Behram</b> (ok. 1765–1840) – przywódca (<i>dżemadar</i>) <a href=\"https://pl.wikipedia.org/wiki/Hinduizm\" target=\"_blank\" rel=\"noopener noreferrer\">hinduistycznej</a> <a href=\"https://pl.wikipedia.org/wiki/Sekta\" target=\"_blank\" rel=\"noopener noreferrer\">sekty</a> <a href=\"https://pl.wikipedia.org/wiki/Thugowie\" target=\"_blank\" rel=\"noopener noreferrer\">thugów</a> – dusicieli zabijających ofiary na cześć bogini <a href=\"https://pl.wikipedia.org/wiki/Kali\" target=\"_blank\" rel=\"noopener noreferrer\">Kali</a>. Funkcję tę sprawował przez blisko 40 lat, póki w 1837 nie został zdradzony przez brytyjskiego informatora i aresztowany. Krótko po zatrzymaniu przyznał się do własnoręcznego uduszenia przy pomocy rytualnego sukna (lub rumāl) 125 osób i nadzorowania uduszenia kolejnych 150, jednak rok później przyznał się do „bycia obecnym” przy 931 morderstwach. Ze względu na tak dużą liczbę <a href=\"https://pl.wikipedia.org/wiki/Zab%C3%B3jstwo\" target=\"_blank\" rel=\"noopener noreferrer\">morderstw</a>, Behram uważany jest za najbardziej wydajnego indywidualnego <a href=\"https://pl.wikipedia.org/wiki/Seryjny_morderca\" target=\"_blank\" rel=\"noopener noreferrer\">seryjnego mordercę</a> w historii. Został skazany na śmierć i powieszony przez Brytyjczyków.", "Bhakti": "<b>Bhakti</b> (<a href=\"https://pl.wikipedia.org/wiki/Sanskryt\" target=\"_blank\" rel=\"noopener noreferrer\">sanskr.</a> <i>bhakti</i> – przywiązanie, miłość; termin zwykle oddawany jako <b>pobożność</b>) – forma religijności w <a href=\"https://pl.wikipedia.org/wiki/Hinduizm\" target=\"_blank\" rel=\"noopener noreferrer\">hinduizmie</a> przejawiająca się głębokim emocjonalnym i intelektualnym oddaniem <a href=\"https://pl.wikipedia.org/wiki/B%C3%B3g\" target=\"_blank\" rel=\"noopener noreferrer\">bogu</a>, której <a href=\"https://pl.wikipedia.org/wiki/Metafora\" target=\"_blank\" rel=\"noopener noreferrer\">metaforą</a> może być miłosny związek z bóstwem, a zarazem niezwykle silny, żywiołowy ruch religijno-społeczny. Osoba praktykująca bhakti nazywana jest <a href=\"https://pl.wikipedia.org/wiki/Bhakta\" target=\"_blank\" rel=\"noopener noreferrer\">bhaktą</a>.", "Benild": "<b>Benild</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_celtyckie\" target=\"_blank\" rel=\"noopener noreferrer\">celtyckiego</a>, którego patronem jest św. <a href=\"https://pl.wikipedia.org/wiki/Benild_Roman%C3%A7on\" target=\"_blank\" rel=\"noopener noreferrer\">Benild</a>, brat zakonny (zm. <a href=\"https://pl.wikipedia.org/wiki/1862\" target=\"_blank\" rel=\"noopener noreferrer\">1862</a>).", "Bogomir": "<b>Bogumił</b>, <b>Bogomił</b>, <b>Bogmił</b>, <b>Bogomieł</b>, <b>Bogmieł</b>, <b>Bogumieł</b> – <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">staropolskie imię</a> męskie. Wywodzi się ze złożenia członów: <i>Bog-</i> („Bóg”, ale pierwotnie w znaczeniu „los, dola, szczęście”) oraz <i>-mił</i> („miły”). Oznacza więc: „miły Bogu” (lecz uprzednio mogło znaczyć „ten, któremu los sprzyja”). <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">Imiona słowiańskie</a> ze składnikami <i>Bog-</i> (np. Bogumił czy Bogusław) mogą być także słowiańskim naśladownictwem irańskich imion używanych w czasach od <a href=\"https://pl.wikipedia.org/wiki/VI_wiek_p.n.e.\" target=\"_blank\" rel=\"noopener noreferrer\">VI</a> do <a href=\"https://pl.wikipedia.org/wiki/IV_wiek_p.n.e.\" target=\"_blank\" rel=\"noopener noreferrer\">IV wieku p.n.e.</a>, takich jak Bagafarna („mający sławę od Boga”).", "Benu": "Imię jego prawdopodobnie wywodziło się od słowa „weben” (wbn), co oznaczało „wznoszący się w blasku” lub „świecący, błyszczący”.", "Barbara": "<b>Barbara</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a> rozpowszechnione za sprawą <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łaciny</a>. Wywodzi się od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;Βαρβάρα (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki_klasyczny\" target=\"_blank\" rel=\"noopener noreferrer\">stgr.</a>&#160;βαρβαρος – każdy kto nie&#160;był Grekiem) oznaczającego „<a href=\"https://pl.wikipedia.org/wiki/Barbarzy%C5%84ca\" target=\"_blank\" rel=\"noopener noreferrer\">barbarzyńcę</a>”, a ściślej od jego łacińskiego odpowiednika w rodzaju żeńskim <i>barbara</i>, co oznacza „barbarzynkę”, czyli <b>cudzoziemkę</b>.", "Bułat": "<b>Bułat</b> – imię pochodzenia gruzińskiego.", "Berengar": "<b>Berengar</b>, Berengariusz – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>, którego patronami jest dwóch św. Berengarów – z <a href=\"https://pl.wikipedia.org/wiki/VII_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">VII</a> i <a href=\"https://pl.wikipedia.org/wiki/XIII_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XIII wieku</a> – wspominanych jednego dnia. Imię to było – również w formie żeńskiej – często spotykane w szlachetnych rodach zachodniej Europy we wczesnych wiekach.", "Bawo": "<b>Bawon</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>, pochodzi od francuskiego <i>bave</i> - ślina lub <i>bavard</i> - gadatliwy, gaduła. Być może powstało jako stopniowe zniekształcanie imiona: Baudo, Baldo, <a href=\"https://pl.wikipedia.org/wiki/Baldwin_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Baldwin</a>.", "Bravo": "<b>Bravo</b> – dwutygodnik dla młodzieży, pochodzący z <a href=\"https://pl.wikipedia.org/wiki/Niemcy\" target=\"_blank\" rel=\"noopener noreferrer\">Niemiec</a>, ukazujący się też w wielu innych krajach Europy. W Polsce pojawił się po raz pierwszy w <a href=\"https://pl.wikipedia.org/wiki/1991\" target=\"_blank\" rel=\"noopener noreferrer\">1991</a> roku i wydawany był przez <a href=\"https://pl.wikipedia.org/wiki/Wydawnictwo_Bauer\" target=\"_blank\" rel=\"noopener noreferrer\">Wydawnictwo Bauer</a>. Redaktorem naczelnym polskiej wersji czasopisma był Michał Wiśnicki. Ostatni numer polskiego wydania <i>Bravo</i> ukazał się w grudniu 2017.", "Bartymeusz": "Syn Tymeusza (Timaiosa), niewidomy, który pod <a href=\"https://pl.wikipedia.org/wiki/Jerycho\" target=\"_blank\" rel=\"noopener noreferrer\">Jerychem</a> wołał <a href=\"https://pl.wikipedia.org/wiki/Jezus_Chrystus\" target=\"_blank\" rel=\"noopener noreferrer\">Jezusa</a>: <i>Synu Dawida, ulituj się nade mną!</i>, a którego Jezus uzdrowił. Patrz <a href=\"https://pl.wikipedia.org/wiki/Ewangelia_Marka\" target=\"_blank\" rel=\"noopener noreferrer\">Mk</a> 10,46 - 52. Ponieważ oba określenia „Bartymeusz” i „syn Tymeusza” znaczą to samo, jego prawdziwe imię nie jest znane. Imię Timaios oznacza po grecku kogoś szanowanego (<i>τιμή</i> 'cześć, szacunek').", "Bina": "<b>Bina</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a> <b>בינה</b>) – określenie oznaczające zrozumienie, inteligencję.", "Beata": "<b>Beata</b> – żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Beat_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Beat</a>, pochodzi od <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>beatus</em> oznaczającego <i>błogosławiona, przynosząca szczęście, szczęśliwa</i>.", "Bożena": "<b>Bożena</b> – żeńskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię pochodzenia słowiańskiego</a>, utworzone poprzez dodanie do rdzenia <i>boż-</i> (od „Bóg”) przyrostka zdrabniającego <i>-ana</i> lub <i>-ena</i>. Imię to zanotowano w dawnych dokumentach w formach <i><b>Bożana</b></i> i <i><b>Bożechna</b></i>, natomiast forma <b>Bożena</b> była znana w języku czeskim, a w Polsce zaczęła się pojawiać regularnie dopiero w <a href=\"https://pl.wikipedia.org/wiki/XIX_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XIX wieku</a>.", "Bogumiła": "<b>Bogumiła</b>, <b>Bogmiła</b> – <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">staropolskie imię</a> żeńskie złożone z członów <i>Bog-</i> („Bóg”, ale pierwotnie „los, dola, szczęście”) i <i>-miła</i> („miła”). Znaczenie imienia „miła Bogu”, lecz pierwotnie mogło ono oznaczać „ta, której los sprzyja”. Odpowiedniki męskie to <a href=\"https://pl.wikipedia.org/wiki/Bogumi%C5%82\" target=\"_blank\" rel=\"noopener noreferrer\">Bogumił</a>, <a href=\"https://pl.wikipedia.org/wiki/Bogumi%C5%82\" target=\"_blank\" rel=\"noopener noreferrer\">Bogomił</a>, <a href=\"https://pl.wikipedia.org/wiki/Bogumi%C5%82\" target=\"_blank\" rel=\"noopener noreferrer\">Bogmił</a>, <a href=\"https://pl.wikipedia.org/wiki/Bogumi%C5%82\" target=\"_blank\" rel=\"noopener noreferrer\">Bogomieł</a> i <a href=\"https://pl.wikipedia.org/wiki/Bogumi%C5%82\" target=\"_blank\" rel=\"noopener noreferrer\">Bogmieł</a>. W źródłach poświadczone od XIII wieku. Występuje w „Sielankach” <a href=\"https://pl.wikipedia.org/wiki/J%C3%B3zef_Bart%C5%82omiej_Zimorowic\" target=\"_blank\" rel=\"noopener noreferrer\">J. B. Zimorowicza</a> i w wierszach Andrzeja Morsztyna.", "Bogusława": "<b>Bogusława</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Bogus%C5%82aw\" target=\"_blank\" rel=\"noopener noreferrer\">Bogusław</a> znany od <a href=\"https://pl.wikipedia.org/wiki/1265\" target=\"_blank\" rel=\"noopener noreferrer\">1265</a> roku. Używane były m.in. zdrobnienia <i>Bogusza</i>, <i>Boguszka</i> i <i>Boguchna</i>. W polskim imiennictwie imię to żywe jest do dziś, ze zdrobnieniami: <i>Bogusia</i> czy <i>Boguśka</i>.", "Bronisława": "<b>Bronisława</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, złożone z członów <i>Broni-</i> („bronić, strzec”) i <i>-sława</i> („sława”). Być może znaczyło „ta, która broni sławy”. W źródłach polskich poświadczone od XIII wieku.", "Bernadeta": "<b>Bernadeta</b>, <b>Bernadetta</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, polski odpowiednik francuskiego imienia <i>Bernadette</i>, które jest zdrobnieniem imienia <i>Bernadet</i> utworzonego od imienia <a href=\"https://pl.wikipedia.org/wiki/Bernard_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Bernard</a>.", "Blanka": "<b>Blanka</b> – imię żeńskie wywodzące się od hiszpańskiej wersji francuskiego imienia <i>Blanche</i> lub z <a href=\"https://pl.wikipedia.org/wiki/Germanie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a> <i>blankus, blanchus</i> „biała”. W niektórych językach występuje również w formie <i><b>Bianka</b></i>.", "Brygida": "<b>Brygida</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Celtowie\" target=\"_blank\" rel=\"noopener noreferrer\">celtyckiego</a>. Pochodzi od imienia bogini celtyckiej <a href=\"https://pl.wikipedia.org/wiki/Brigid\" target=\"_blank\" rel=\"noopener noreferrer\">Brigid</a> lub od słów <i>brigh</i> „siła”, „męstwo”, „cnota”, <i>briganti</i> „wysoki”. Jego pierwotne znaczenie można objaśnić jako „wysoka”, „dostojna”, „potężna”. Imię to pojawiło się w Polsce już w średniowieczu, zapisywano je jako Brygida, Bryjida, Bryda, Bryta, Brytnia. Najstarszy zapis pochodzi z 1265 roku. W 2001 roku miało tak na imię 17456 Polek (255. miejsce wśród wszystkich imion nadanych w Polsce). Były one najczęściej urodzone w latach 50. i 60. XX wieku.", "Bożenna": "<b>Bożena</b> – żeńskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię pochodzenia słowiańskiego</a>, utworzone poprzez dodanie do rdzenia <i>boż-</i> (od „Bóg”) przyrostka zdrabniającego <i>-ana</i> lub <i>-ena</i>. Imię to zanotowano w dawnych dokumentach w formach <i><b>Bożana</b></i> i <i><b>Bożechna</b></i>, natomiast forma <b>Bożena</b> była znana w języku czeskim, a w Polsce zaczęła się pojawiać regularnie dopiero w <a href=\"https://pl.wikipedia.org/wiki/XIX_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XIX wieku</a>.", "Bernadetta": "<b>Bernadeta</b>, <b>Bernadetta</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, polski odpowiednik francuskiego imienia <i>Bernadette</i>, które jest zdrobnieniem imienia <i>Bernadet</i> utworzonego od imienia <a href=\"https://pl.wikipedia.org/wiki/Bernard_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Bernard</a>.", "Bianka": "<b>Blanka</b> – imię żeńskie wywodzące się od hiszpańskiej wersji francuskiego imienia <i>Blanche</i> lub z <a href=\"https://pl.wikipedia.org/wiki/Germanie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a> <i>blankus, blanchus</i> „biała”. W niektórych językach występuje również w formie <i><b>Bianka</b></i>.", "Bernarda": "<b>Bernarda</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>, żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Bernard_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Bernard</a>", "Bogna": "<b>Bogna</b> – <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">staropolskie imię</a> żeńskie stanowiące formę pochodną (zdrobniałą) od imion rozpoczynających się na <i>Bog-</i>, początkowo zarówno męską, jak i żeńską. Istnieją również hipotezy, że imię to mogło być wymyślone przez kronikarza <a href=\"https://pl.wikipedia.org/wiki/Jan_D%C5%82ugosz\" target=\"_blank\" rel=\"noopener noreferrer\">Jana Długosza</a>, w którego pismach pojawia się po raz pierwszy, lub służyć jako zdrobnienie od imienia <a href=\"https://pl.wikipedia.org/wiki/Benigna\" target=\"_blank\" rel=\"noopener noreferrer\">Benigna</a>. W źródłach polskich poświadczone w XV wieku.", "Bolesława": "<b>Bolesława</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Boles%C5%82aw_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Bolesław</a>. Forma ta jest notowana w Polsce od <a href=\"https://pl.wikipedia.org/wiki/XV_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XV wieku</a>.", "Balbina": "<b>Balbina</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Balbin_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Balbin</a> o pochodzeniu łacińskim.", "Bernardyna": "<b>Bernardyna</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Bernardyn_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Bernardyn</a>. Patronką tego imienia jest św. Bernardyna z <a href=\"https://pl.wikipedia.org/wiki/Foligno\" target=\"_blank\" rel=\"noopener noreferrer\">Foligno</a>.", "Berenika": "W Polsce między 1901 a 1994 rokiem imię to nadano&#160;<b>414</b>&#160;razy: w latach 20. odnotowano&#160;je <b>1</b>&#160;raz, w latach 30., 40. i 50. nie odnotowano&#160;ani jednej&#160;Bereniki. W latach 60. XX wieku było ich <b>34</b> a 104 w latach 70. Najwięcej, bo aż <b>221</b>&#160; nadań tego imienia odnotowano w latach 80. Pomiędzy 1991 a kwietniem 1994 roku zarejestrowano&#160;<b>54</b>&#160;Bereniki.", "Benedykta": "<b>Benedykta</b> – żeńska forma <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Benedykt\" target=\"_blank\" rel=\"noopener noreferrer\">Benedykt</a>. Może też występować w formie <b>Benita</b>.", "Bogdana": "<b>Bogdana</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, złożone z członu <i>Bog-</i> („Bóg”, „Boga”, ale pierwotnie „los, dola, szczęście”) i <i>-dana</i> („dana”). Imię to mogło oznaczać „dana przez los”, później „dana przez Boga”. W źródłach polskich poświadczone od XIII wieku.", "Berta": "<b>Berta</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>, wywodzące się od przymiotnika <i>beraht</i> – „lśniący, błyszczący”; pierwotnie <a href=\"https://pl.wikipedia.org/wiki/Zdrobnienie\" target=\"_blank\" rel=\"noopener noreferrer\">zdrobnienie</a> od imion z takim pierwszym lub drugim członem, np. Bertylda, Amalberta, <a href=\"https://pl.wikipedia.org/wiki/Bertrada\" target=\"_blank\" rel=\"noopener noreferrer\">Bertrada</a>, <a href=\"https://pl.wikipedia.org/wiki/Adalberta\" target=\"_blank\" rel=\"noopener noreferrer\">Adalberta</a>. W <a href=\"https://pl.wikipedia.org/wiki/Polska\" target=\"_blank\" rel=\"noopener noreferrer\">Polsce</a> zapisywane co najmniej od <a href=\"https://pl.wikipedia.org/wiki/XIII_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XIII wieku</a>, w formach Berta (poświadczona w <a href=\"https://pl.wikipedia.org/wiki/1252\" target=\"_blank\" rel=\"noopener noreferrer\">1252</a> roku), <i>Berchta</i>, Breta i ze zdrobnieniem Bretka.", "Blandyna": "<b>Blandyna</b> – żeńska forma imienia <a href=\"https://pl.wikipedia.org/wiki/Blandyn\" target=\"_blank\" rel=\"noopener noreferrer\">Blandyn</a>, utworzona od <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a> przymiotnika <i>blandinus</i> (ż. <i>blandina</i>), w znaczeniu „powabny, wdzięczny, czarujący, ew. uprzejmy, przyjacielski”.", "Bernardeta": "<b>Bernadeta</b>, <b>Bernadetta</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, polski odpowiednik francuskiego imienia <i>Bernadette</i>, które jest zdrobnieniem imienia <i>Bernadet</i> utworzonego od imienia <a href=\"https://pl.wikipedia.org/wiki/Bernard_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Bernard</a>.", "Benita": "<b>Benedykta</b> – żeńska forma <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Benedykt\" target=\"_blank\" rel=\"noopener noreferrer\">Benedykt</a>. Może też występować w formie <b>Benita</b>.", "Benigna": "<b>Benigna</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, odpowiednik męskiego imienia <a href=\"https://pl.wikipedia.org/wiki/Benigny\" target=\"_blank\" rel=\"noopener noreferrer\">Benignus</a>, <a href=\"https://pl.wikipedia.org/wiki/Benigny\" target=\"_blank\" rel=\"noopener noreferrer\">Benigny</a>. Pochodzi od przymiotnika <i>benigna</i>, oznaczającego „dobroduszna, uprzejma, przyjazna, życzliwa”, który następnie stał się <a href=\"https://pl.wikipedia.org/wiki/Nazwisko#Przydomek_(cognomen)\" target=\"_blank\" rel=\"noopener noreferrer\">przydomkiem</a>, a później imieniem. W Polsce po raz pierwszy zanotowane w XIV wieku, jednak w odniesieniu do osoby żyjącej w wieku XI. Patronką tego imienia jest <a href=\"https://pl.wikipedia.org/wiki/Benigna_z_Wroc%C5%82awia\" target=\"_blank\" rel=\"noopener noreferrer\">bł. Benigna z Wrocławia</a> (lub <a href=\"https://pl.wikipedia.org/wiki/Trzebnica\" target=\"_blank\" rel=\"noopener noreferrer\">Trzebnicy</a>).", "Betina": "Pierwsza wzmianka o Betinie pochodzi z 1423 roku. W 1573 roku, w Betinie osiedlili się uchodźcy z miejscowości Vrana, którzy szukali schronienia przed tureckimi wojskami.", "Beatrycze": "<b>Beatrycze</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_w%C5%82oski\" target=\"_blank\" rel=\"noopener noreferrer\">włoskiego</a>. Wywodzi się od słowa oznaczającego „przynosząca szczęście”. Użyte w <i><a href=\"https://pl.wikipedia.org/wiki/Boska_komedia\" target=\"_blank\" rel=\"noopener noreferrer\">Boskiej komedii</a></i> <a href=\"https://pl.wikipedia.org/wiki/Dante_Alighieri\" target=\"_blank\" rel=\"noopener noreferrer\">Dantego</a>.", "Brenda": "<b>Brenda</b> – żeńskie imię, które jest odpowiednikiem męskiego imienia <a href=\"https://pl.wikipedia.org/wiki/Brendan\" target=\"_blank\" rel=\"noopener noreferrer\">Brendan</a>. Imię popularne w kulturze amerykańskiej i angielskiej.", "Biruta": "<b>Biruta</b> (<i>Birutė</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_litewski\" target=\"_blank\" rel=\"noopener noreferrer\">litewskiego</a>. Wywodzi się od słowa <i>birti</i> oznaczającego: „rozpraszać”, „wylewać”.", "Bibiana": "<b>Bibiana</b>, <b>Bibianna</b>, <b>Wiwiana</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie utworzone od <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiej</a> nazwy rodu <i>Vivius</i> i oznaczające „należąca do rodu <i>Vivii</i>”. Z kolei owa łacińska nazwa rodowa wywodzi się od łac. przymiotnika <i>vivus</i>, oznaczającego „żywy, żwawy”. Wymiana <i>W</i> na <i>B</i> odzwierciedla ludową włoską i hiszpańską wymowę tego imienia. W Polsce nadawane co najmniej od 1755 roku.", "Bernardetta": "<b>Bernadeta</b>, <b>Bernadetta</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, polski odpowiednik francuskiego imienia <i>Bernadette</i>, które jest zdrobnieniem imienia <i>Bernadet</i> utworzonego od imienia <a href=\"https://pl.wikipedia.org/wiki/Bernard_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Bernard</a>.", "Betty": "<b>Betty</b> – <a href=\"https://pl.wikipedia.org/wiki/Anglia\" target=\"_blank\" rel=\"noopener noreferrer\">angielskie</a> imię. Jest to zdrobnienie od imienia Elizabeth (<a href=\"https://pl.wikipedia.org/wiki/El%C5%BCbieta\" target=\"_blank\" rel=\"noopener noreferrer\">Elżbieta</a>).", "Belinda": "Belinda – imię żeńskie o niejasnym pochodzeniu, być może angielskim lub niemieckim.", "Bożysława": "<b>Borzysława</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Borzys%C5%82aw_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Borzysław</a>, nienotowany w czasach staropolskich.", "Bona": "<b>Bona</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie oznaczające \"dobra\". Łacińskie słowo, od którego imię to pochodzi (<i>bonus</i> — \"dobry\"; <i>bona</i> — \"dobra\") nie ma pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_indoeuropejskie\" target=\"_blank\" rel=\"noopener noreferrer\">indoeuropejskiego</a>.", "Boguchwała": "<b>Boguchwała</b>, <b>Bogufała</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, złożone z członu <i>Bogu-</i> (\"Bóg\", ale pierwotnie \"los, dola, szczęście\") i <i>-chwała</i> (\"chwalić, sławić, dziękować\"). Prawdopodobnie oznaczało \"tę, która sławi szczęście\", późn. \"tę, która sławi Boga\". W źródłach polskich poświadczone od XIII wieku.", "Bonifacja": "<b>Bonifacja</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od słów <i>bonum fatum</i> oznaczających „dobry los”. Patronką tego imienia jest św. <a href=\"https://pl.wikipedia.org/wiki/Bonifacja_Rodr%C3%ADguez_Castro\" target=\"_blank\" rel=\"noopener noreferrer\">Bonifacja Rodríguez Castro</a>.", "Bermet": "<b>Bermet</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_serbski\" target=\"_blank\" rel=\"noopener noreferrer\">serb.</a>&#160;<a href=\"https://pl.wikipedia.org/wiki/Cyrylica_serbska\" target=\"_blank\" rel=\"noopener noreferrer\">cyr.</a> Бермет) – <a href=\"https://pl.wikipedia.org/wiki/Wino_deserowe\" target=\"_blank\" rel=\"noopener noreferrer\">wino deserowe</a> pochodzące z regionu <a href=\"https://pl.wikipedia.org/wiki/Fru%C5%A1ka_gora\" target=\"_blank\" rel=\"noopener noreferrer\">Fruška gora</a> w <a href=\"https://pl.wikipedia.org/wiki/Wojwodina\" target=\"_blank\" rel=\"noopener noreferrer\">Wojwodinie</a>. Początkowo przeznaczony był do zastosowań medycznych (trawienie), następnie produkowany do powszechnej konsumpcji. Bermet zawiera od 16 do 18 procent alkoholu, zazwyczaj podawany jest jako wino deserowe, ale może również być podany jako <a href=\"https://pl.wikipedia.org/wiki/Aperitif\" target=\"_blank\" rel=\"noopener noreferrer\">aperitif</a>. Zaleca się podawanie wina w temperaturze 18-20 °C. Nazwa wina pochodzi od zniekształconego słowa <a href=\"https://pl.wikipedia.org/wiki/Wermut\" target=\"_blank\" rel=\"noopener noreferrer\">wermut</a>, wytwarzany jest jednak inaczej niż wermut, poprzez macerację minimum 20 ziół i przypraw. Wytwarzany jest zarówno z białych jak i czerwonych winogron. Dokładny przepis pozostaje tajny i obecnie jest w posiadaniu kilku rodzin z miasta <a href=\"https://pl.wikipedia.org/wiki/Sremski_Karlovci\" target=\"_blank\" rel=\"noopener noreferrer\">Sremski Karlovci</a>. Według niektórych relacji, Bermet był serwowany na <a href=\"https://pl.wikipedia.org/wiki/Titanic\" target=\"_blank\" rel=\"noopener noreferrer\">Titanicu</a>, jak również w Królewskim Pałacu w Wiedniu. Bermet jest zarejestrowanym chronionym oznaczeniem geograficznym w Urzędzie Własności Intelektualnej Republiki Serbii.", "Balladyna": "<b>Balladyna</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia literackiego, imię tytułowej bohaterki <a href=\"https://pl.wikipedia.org/wiki/Dramat\" target=\"_blank\" rel=\"noopener noreferrer\">dramatu</a> <a href=\"https://pl.wikipedia.org/wiki/Romantyzm\" target=\"_blank\" rel=\"noopener noreferrer\">romantycznego</a> <a href=\"https://pl.wikipedia.org/wiki/Juliusz_S%C5%82owacki\" target=\"_blank\" rel=\"noopener noreferrer\">Juliusza Słowackiego</a> <i><a href=\"https://pl.wikipedia.org/wiki/Balladyna\" target=\"_blank\" rel=\"noopener noreferrer\">Balladyna</a></i>.", "Benona": "<b>Benona</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie; żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Benon_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Benon</a>, powstałego jako zdrobnienie od imienia <a href=\"https://pl.wikipedia.org/wiki/Bernard_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Bernard</a>.", "Bratumiła": "<b>Bratumiła</b>, <b>Bratomiła</b>, <b>Bratmiła</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, złożone z członów <i>Bratu-</i> (\"bratu\", \"członkowi wspólnoty rodowej\", \"człowiekowi bliskiemu\") i <i>-miła</i> (\"miła\"). Znaczenie imienia: \"miła swoim bliskim\". W źródłach polskich poświadczone w XIII wieku (1265 rok).", "Bonita": "<b>Bonita</b> – żeńskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskie</a>, oznaczające \"człowieka o dobrym sercu\", pierwotnie pochodzące od zdrobnienia od przymiotnika <i>bonus</i> — \"dobry\". Patronem tego imienia jest św. Bonet (Bonitus).", "Beatris": "<b>Beatrycze</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_w%C5%82oski\" target=\"_blank\" rel=\"noopener noreferrer\">włoskiego</a>. Wywodzi się od słowa oznaczającego „przynosząca szczęście”. Użyte w <i><a href=\"https://pl.wikipedia.org/wiki/Boska_komedia\" target=\"_blank\" rel=\"noopener noreferrer\">Boskiej komedii</a></i> <a href=\"https://pl.wikipedia.org/wiki/Dante_Alighieri\" target=\"_blank\" rel=\"noopener noreferrer\">Dantego</a>.", "Borzysława": "<b>Borzysława</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Borzys%C5%82aw_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Borzysław</a>, nienotowany w czasach staropolskich.", "Beatricze": "<b>Beatrycze</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_w%C5%82oski\" target=\"_blank\" rel=\"noopener noreferrer\">włoskiego</a>. Wywodzi się od słowa oznaczającego „przynosząca szczęście”. Użyte w <i><a href=\"https://pl.wikipedia.org/wiki/Boska_komedia\" target=\"_blank\" rel=\"noopener noreferrer\">Boskiej komedii</a></i> <a href=\"https://pl.wikipedia.org/wiki/Dante_Alighieri\" target=\"_blank\" rel=\"noopener noreferrer\">Dantego</a>.", "Budzisława": "<b>Budzisława</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, złożone z członów <i>Budzi-</i> (\"budzić\") i <i>-sława</i> (\"sława\"). Mogło oznaczać \"ta, która zyskuje sławę\". Staropolskie zdrobnienie: Buchna. W źródłach polskich poświadczone w XIV wieku (1362 rok).", "Borzyna": "<b>Borzymir</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, złożone z członów <i>Borzy-</i> (\"walczyć\", \"walka\") oraz <i>-mir</i> (\"pokój\"). Mogło oznaczać \"ten, który walczy o pokój\".", "Bazyla": "<b>Bazyla</b>, <b>Bazylia</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia greckiego. Pochodzi ono od przymiotnika utworzonego od rzeczownika <i>basileus</i> – „król, wódz, cesarz”. Oznacza więc „królewska”.", "Bhavana": "<b>Bhavana</b> (<i><a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_palijski\" target=\"_blank\" rel=\"noopener noreferrer\">pali</a>: bhāvanā</i>) oznacza \"rozwój\" (dosłownie \"przywoływanie do istnienia, produkowanie\"). W naukach <a href=\"https://pl.wikipedia.org/wiki/Budda_Siakjamuni\" target=\"_blank\" rel=\"noopener noreferrer\">Buddy</a> termin ten jest często używany w połączeniu z innymi wyrazami w takich frazach, jak:", "Błażeja": "<b>Błażeja</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od słowa oznaczającego \"seplenić\". Żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/B%C5%82a%C5%BCej\" target=\"_blank\" rel=\"noopener noreferrer\">Błażej</a>.", "Benilda": "<b>Benilda</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>, którego patronką jest św. Benilda, żyjąca w <a href=\"https://pl.wikipedia.org/wiki/Kordowa\" target=\"_blank\" rel=\"noopener noreferrer\">Kordowie</a> (<a href=\"https://pl.wikipedia.org/wiki/Hiszpania\" target=\"_blank\" rel=\"noopener noreferrer\">Hiszpania</a>), w <a href=\"https://pl.wikipedia.org/wiki/IX_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">IX wieku</a>.", "Birutė": "<b>Biruta</b> (<i>Birutė</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_litewski\" target=\"_blank\" rel=\"noopener noreferrer\">litewskiego</a>. Wywodzi się od słowa <i>birti</i> oznaczającego: „rozpraszać”, „wylewać”.", "Brandy": "Nazwa pochodzi od <a href=\"https://pl.wikipedia.org/wiki/Holandia\" target=\"_blank\" rel=\"noopener noreferrer\">holenderskiego</a> słowa <i>brandewijn</i> („destylowane wino”). Staropolska, do dziś poprawna i używana nazwa brandy to <i>wypalanka</i>. Tak określa się <a href=\"https://pl.wikipedia.org/wiki/W%C3%B3dka\" target=\"_blank\" rel=\"noopener noreferrer\">wódki</a> destylowane w tradycyjny sposób, „wypalane” w aparatach destylacyjnych, a już nie wódki <a href=\"https://pl.wikipedia.org/wiki/Rektyfikacja_(destylacja)\" target=\"_blank\" rel=\"noopener noreferrer\">rektyfikowane</a>. Niekiedy nazywana jest również błędnie <i>przepalanką</i>, mimo że termin odnosi się do destylatów produkowanych na bazie <a href=\"https://pl.wikipedia.org/wiki/Karmel\" target=\"_blank\" rel=\"noopener noreferrer\">karmelu</a>.", "Bilkis": "<b>Makeda</b> – pierwsza znana królowa <a href=\"https://pl.wikipedia.org/wiki/Kr%C3%B3lestwo_Saba\" target=\"_blank\" rel=\"noopener noreferrer\">Saby</a>. Makeda to imię wywodzące się z tradycji <a href=\"https://pl.wikipedia.org/wiki/Etiopia\" target=\"_blank\" rel=\"noopener noreferrer\">etiopskiej</a>; w <a href=\"https://pl.wikipedia.org/wiki/Islam\" target=\"_blank\" rel=\"noopener noreferrer\">islamskich</a> przekazach nazywana była Bilkis (<b>بلقيس</b> <i>Bilqīs</i>). Inne wersje jej imienia to Nikaule oraz Nicaula.", "Beatriks": "<b>Beatrycze</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_w%C5%82oski\" target=\"_blank\" rel=\"noopener noreferrer\">włoskiego</a>. Wywodzi się od słowa oznaczającego „przynosząca szczęście”. Użyte w <i><a href=\"https://pl.wikipedia.org/wiki/Boska_komedia\" target=\"_blank\" rel=\"noopener noreferrer\">Boskiej komedii</a></i> <a href=\"https://pl.wikipedia.org/wiki/Dante_Alighieri\" target=\"_blank\" rel=\"noopener noreferrer\">Dantego</a>.", "Beta": "<b>Beta</b> (<b>wita</b>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki_klasyczny\" target=\"_blank\" rel=\"noopener noreferrer\">stgr.</a>&#160;βῆτα, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_nowogrecki\" target=\"_blank\" rel=\"noopener noreferrer\">nw.gr.</a> <b>βήτα</b>, pisana <b>Ββ</b> lub <b>ϐ</b>) – druga <a href=\"https://pl.wikipedia.org/wiki/Litera\" target=\"_blank\" rel=\"noopener noreferrer\">litera</a> <a href=\"https://pl.wikipedia.org/wiki/Alfabet_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">alfabetu greckiego</a>. W <a href=\"https://pl.wikipedia.org/wiki/Grecki_system_liczbowy\" target=\"_blank\" rel=\"noopener noreferrer\">greckim systemie liczbowym</a> oznaczała liczbę <a href=\"https://pl.wikipedia.org/wiki/2_(liczba)\" target=\"_blank\" rel=\"noopener noreferrer\">2</a>. Beta pochodzi od litery <a href=\"https://pl.wikipedia.org/wiki/Alfabet_fenicki\" target=\"_blank\" rel=\"noopener noreferrer\">alfabetu fenickiego</a> bet <a href=\"https://pl.wikipedia.org/wiki/Plik:Phoenician_beth.svg\" target=\"_blank\" rel=\"noopener noreferrer\"></a>. Od bety pochodzą <a href=\"https://pl.wikipedia.org/wiki/Alfabet_%C5%82aci%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskie</a> <a href=\"https://pl.wikipedia.org/wiki/B\" target=\"_blank\" rel=\"noopener noreferrer\">B</a> i <a href=\"https://pl.wikipedia.org/wiki/Cyrylica\" target=\"_blank\" rel=\"noopener noreferrer\">cyrylickie</a> <a href=\"https://pl.wikipedia.org/wiki/%D0%91\" target=\"_blank\" rel=\"noopener noreferrer\">Б</a> i <a href=\"https://pl.wikipedia.org/wiki/%D0%92\" target=\"_blank\" rel=\"noopener noreferrer\">В</a>.", "Bartłomieja": "<b>Bartłomieja</b> – forma żeńska <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Bart%C5%82omiej\" target=\"_blank\" rel=\"noopener noreferrer\">Bartłomiej</a>. W Polsce w tej formie imię nie jest używane. Zapisywana jako Bartolomea imieniny obchodzi <a href=\"https://pl.wikipedia.org/wiki/26_lipca\" target=\"_blank\" rel=\"noopener noreferrer\">26 lipca</a>.", "Bree": "<b>Bree</b> – żeńskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> pochodzenia celtycko-irlandzkiego spokrewnione z imionami <a href=\"https://pl.wikipedia.org/wiki/Brygida\" target=\"_blank\" rel=\"noopener noreferrer\">Brygida</a> (<i>Bridget</i>), Brianna i <a href=\"https://pl.wikipedia.org/wiki/Sabrina_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Sabrina</a>. Występuje też w wariantach Breehan i Brighe.", "Begonia": "<b>Begonia</b>, ukośnica (<i>Begonia</i> L.) – <a href=\"https://pl.wikipedia.org/wiki/Rodzaj_(biologia)\" target=\"_blank\" rel=\"noopener noreferrer\">rodzaj</a> roślin z rodziny <a href=\"https://pl.wikipedia.org/wiki/Begoniowate\" target=\"_blank\" rel=\"noopener noreferrer\">begoniowatych</a> obejmujący według różnych autorów 1200–1500 <a href=\"https://pl.wikipedia.org/wiki/Gatunek_(biologia)\" target=\"_blank\" rel=\"noopener noreferrer\">gatunków</a>. Występują na wszystkich, z wyjątkiem Australii obszarach tropikalnych i subtropikalnych kuli ziemskiej, najliczniejsza grupa gatunków występuje w Ameryce Południowej. Jest to jeden z najbardziej obfitujących w gatunki rodzajów roślin. Należą do niego popularne na całym świecie <a href=\"https://pl.wikipedia.org/wiki/Ro%C5%9Bliny_ozdobne\" target=\"_blank\" rel=\"noopener noreferrer\">rośliny ozdobne</a>. Nazwa rodzaju pochodzi od nazwiska francuskiego botanika M. Begona. <a href=\"https://pl.wikipedia.org/wiki/Gatunek_typowy\" target=\"_blank\" rel=\"noopener noreferrer\">Gatunkiem typowym</a> jest <i> Begonia obliqua</i> L.", "Barbie": "Nazwa Barbie jest <a href=\"https://pl.wikipedia.org/wiki/Zdrobnienie\" target=\"_blank\" rel=\"noopener noreferrer\">zdrobnieniem</a> od imienia córki Ruth Handler, Barbary, dla której Ruth kupiła egzemplarz Lilli podczas pobytu w <a href=\"https://pl.wikipedia.org/wiki/Szwajcaria\" target=\"_blank\" rel=\"noopener noreferrer\">Szwajcarii</a>. Pełne nazwisko lalki to <b>Barbara Millicent Roberts</b>. Stanowi ono tylko część wymyślonej biografii, w której występują między innymi chłopak Barbie – <a href=\"https://pl.wikipedia.org/wiki/Ken_Carson\" target=\"_blank\" rel=\"noopener noreferrer\">Ken</a> i jej przyjaciółki – <a href=\"https://pl.wikipedia.org/wiki/Midge\" target=\"_blank\" rel=\"noopener noreferrer\">Midge</a> i Teresa. Barbie ma również trzy młodsze siostry o imionach Skipper, Stacie i Chelsea.", "Bratomiła": "<b>Bratumiła</b>, <b>Bratomiła</b>, <b>Bratmiła</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, złożone z członów <i>Bratu-</i> (\"bratu\", \"członkowi wspólnoty rodowej\", \"człowiekowi bliskiemu\") i <i>-miła</i> (\"miła\"). Znaczenie imienia: \"miła swoim bliskim\". W źródłach polskich poświadczone w XIII wieku (1265 rok).", "Blanda": "<b>Blanda</b> — <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81ac.\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, oznaczające \"czarująca\". Od tego imienia wywodzi się imię <a href=\"https://pl.wikipedia.org/wiki/Blandyna\" target=\"_blank\" rel=\"noopener noreferrer\">Blandyna</a>. Jego patronką jest św. Blanda, wspominana razem ze św. Symplicjuszem i Feliksem.", "Beatryks": "<b>Beatrycze</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_w%C5%82oski\" target=\"_blank\" rel=\"noopener noreferrer\">włoskiego</a>. Wywodzi się od słowa oznaczającego „przynosząca szczęście”. Użyte w <i><a href=\"https://pl.wikipedia.org/wiki/Boska_komedia\" target=\"_blank\" rel=\"noopener noreferrer\">Boskiej komedii</a></i> <a href=\"https://pl.wikipedia.org/wiki/Dante_Alighieri\" target=\"_blank\" rel=\"noopener noreferrer\">Dantego</a>."};
